import { z } from 'zod';

export const E2E421ClientActionSchema = z.object({
  scenarioId: z.literal('e2e-421'),
  fixture: z.enum(['authorized_same_tenant', 'cross_tenant_denied', 'expired_role_grant', 'permission_denied']),
  action: z.enum(['submit_request', 'change_role', 'load_protected_resource', 'retry_after_refresh']),
  idempotencyKey: z.string().uuid(),
}).strict();

export const E2E421TrustedContextSchema = z.object({
  actorId: z.string().min(1),
  tenantId: z.string().min(1),
  role: z.enum(['owner','admin','member','viewer','system']),
  sessionId: z.string().min(1),
}).strict();

export const E2E421ResultSchema = z.object({
  status: z.enum(['passed','failed','denied','retryable_error']),
  httpStatus: z.union([z.literal(200), z.literal(202), z.literal(400), z.literal(403), z.literal(409), z.literal(422), z.literal(500)]),
  code: z.enum(['AUTHORIZED', 'DENIED', 'ROLE_EXPIRED', 'CSRF_OR_SESSION_INVALID', 'PERMISSION_DENIED']),
  userMessage: z.string().min(1),
  assertion: z.object({
    visibleState: z.literal('permission_boundary_visible'),
    scenarioTitle: z.literal('Tenant settings export/import for migration'),
    redactedTelemetry: z.object({ event: z.literal('e2e.e2e-421.checked'), category: z.literal('saas_multi_tenancy'), redacted: z.literal(true) }),
  }),
}).strict();

backend_solution:
// e2e-421: typed route for Tenant settings export/import for migration
export async function handleE2E421(req, ctx) {
  const input = E2E421Schema.parse(await req.json());
  const authz = await ctx.authz.assertCan(input.actorId, 'saas_multi_tenancy', input.tenantId);
  const result = await ctx.db.transaction(tx => ctx.flows.tenant_settings_export_import_for(tx, input, authz));
  ctx.metrics.observe('error_rate', result.metric);
  return Response.json(ResultSchema.parse(result));
}

frontend_solution:
export function E2E421Probe() {
  const [state, run] = useScenarioProbe('e2e-421', ['happy_path','denied','retry','rollback']);
  return <form aria-label='Tenant settings export/import for migration' onSubmit={run}><output role='status'>{state.message}</output><button>Run</button></form>;
